    req.socket.join(roomId);

    // Notify both clients that they have been matched and provide them with the room ID
    io.to(client.socket.id).emit(`matched`, roomId);
    io.to(req.socket.id).emit(`matched`, roomId);

    return res.status(200).json({ roomId });
  }

  return res.status(404).json({ message: `No match found for tags: ${tags}` });
});

io.on(`connection`, (socket) => {
  console.log(`connected: `, socket.id);

  socket.on(`setTags`, (tags) => {
    console.log(`Client with ${tags}`);

    availableClients.push({ socket, tags });
  });

